struct FileInfo {
  std::string currentFile;
  int currentLineOffset;
  int baseLine;
};

// Parse preprocessor directive to update file info
void parsePreprocessorDirective(const std::string& line, FileInfo& fileInfo) {
  std::regex directivePattern(R"(^#\s+(\d+)\s+"([^"]+)"(\s+\d+)?)");
  std::smatch matches;

  if (std::regex_search(line, matches, directivePattern)) {
    int lineNum = std::stoi(matches[1].str());
    std::string filename = matches[2].str();

    fileInfo.currentFile = filename;
    fileInfo.baseLine = lineNum;
    fileInfo.currentLineOffset = 0;
  }
}

void
print_token(const antlr4::Token* token,
            antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer,
            const FileInfo& fileInfo)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // Get location information
  int actualLine = fileInfo.baseLine + token->getLine() - 1;
  std::string locInfo = " Loc=<" + fileInfo.currentFile + ":" + std::to_string(actualLine) + ":" +
                        std::to_string(token->getCharPositionInLine() + 1) +
                        ">";

  // Check for StartOfLine and LeadingSpace
  bool startOfLine = token->getCharPositionInLine() == 0;
  bool leadingSpace = false;

  // Check if previous token exists and if there's a space between tokens
  auto prevToken = token;
  auto tokenIndex = token->getTokenIndex();
  if (tokenIndex > 0) {
    auto allTokens = tokens.getTokens();
    if (tokenIndex < allTokens.size()) {
      auto prevToken = allTokens[tokenIndex - 1];
      // Check if there's a gap between tokens (indicating whitespace)
      if (prevToken->getStopIndex() + 1 < token->getStartIndex()) {
        leadingSpace = true;
      }
    }
  }

  if (tokenTypeName == "eof") {
    outFile << "eof ''" << locInfo << std::endl;
  } else {
    outFile << tokenTypeName << " '" << token->getText() << "'";
    if (startOfLine)
      outFile << "\t [StartOfLine]";
    if (leadingSpace)
      outFile << " [LeadingSpace]";
    outFile << locInfo << std::endl;
  }
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
