  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  // Read the entire input to process preprocessor directives
  std::string content((std::istreambuf_iterator<char>(inFile)),
                      std::istreambuf_iterator<char>());

  // Process preprocessor directives and create clean input for lexer
  std::string cleanInput;
  FileInfo fileInfo;
  fileInfo.currentFile = "";
  fileInfo.currentLineOffset = 0;
  fileInfo.baseLine = 1;

  std::istringstream contentStream(content);
  std::string line;
  while (std::getline(contentStream, line)) {
    if (line.empty()) continue;

    if (line[0] == '#') {
      parsePreprocessorDirective(line, fileInfo);
      // Skip preprocessor directives in the clean input
      cleanInput += "\n";  // Add newline to maintain line count
