    69	        TASK4_DIR "/Mem2Reg.hpp",
    70	        TASK4_DIR "/Mem2Reg.cpp",
    71	        "Mem2Reg.xml",
    72	        [](llvm::ModulePassManager& mpm) { mpm.addPass(Mem2Reg()); } },
    73	      { "ConstantFolding",
    74	        TASK4_DIR "/ConstantFolding.hpp",
    75	        TASK4_DIR "/ConstantFolding.cpp",
    76	        "ConstantFolding.xml",
